from pydantic_ai import Agent, Result
from pydantic import ValidationError
import logging

class CoordinationMonitor:
    def __init__(self):
        self.validation_errors = 0
        self.total_calls = 0

    def result_validator(self, result: Result) -> Result:
        try:
            self.total_calls += 1
            return result
        except ValidationError as e:
            self.validation_errors += 1
            logging.error(f"Coordination validation failed: {e}")
            if self.validation_errors > self.total_calls * 0.1:
                raise RuntimeError("High coordination failure rate detected")
            raise

monitor = CoordinationMonitor()
agent = Agent(result_validator=monitor.result_validator)

