from pydantic_ai import Agent, Result
from functools import wraps
import time

class ContextPreservingRetry:
    def __init__(self, max_retries: int = 3):
        self.max_retries = max_retries

    def __call__(self, fn):
        @wraps(fn)
        async def wrapper(*args, context=None, **kwargs):
            last_error = None
            for attempt in range(self.max_retries):
                try:
                    result = await fn(*args, context=context, **kwargs)
                    return result
                except Exception as e:
                    last_error = e
                    if 'coordination' in (context or {}):
                        # Preserve coordination context on retry
                        time.sleep(0.1 * (2 ** attempt))
                    else:
                        raise
            raise last_error
        return wrapper

retry_policy = ContextPreservingRetry()
agent = Agent(run=retry_policy(agent.run))
